SELECT *
FROM audit_record


        AND audit_type = #{auditType}


        AND audit_status = #{auditStatus}


        AND target_name LIKE CONCAT('%', #{targetName}, '%')


        AND applicant_name LIKE CONCAT('%', #{applicantName}, '%')


        AND created_time  >=  #{startTime}


        AND created_time  <=  #{endTime}


ORDER BY created_time DESC, id DESC

SELECT audit_type AS auditType, COUNT(1) AS totalCount, SUM(CASE WHEN audit_status = 'PENDING' THEN 1 ELSE 0 END) AS pendingCount, SUM(CASE WHEN audit_status = 'APPROVED' THEN 1 ELSE 0 END) AS approvedCount, SUM(CASE WHEN audit_status = 'REJECTED' THEN 1 ELSE 0 END) AS rejectedCount FROM audit_record
AND audit_type = #{auditType}
GROUP BY audit_type ORDER BY audit_type ASC

SELECT *
FROM audit_record
WHERE audit_type = #{auditType}
  AND target_id = #{targetId}
ORDER BY id DESC
LIMIT 1
